#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#pragma OPENCL EXTENSION cl_khr_fp16 : enable

#ifdef ENABLE_DP
#if !defined(__DOUBLE__)
#define __DOUBLE__
#endif
#endif

#ifdef ENABLE_HP
#if !defined(__HALF__)
#define __HALF__
#endif
#endif

#ifndef class_T
#define class_T float
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 8
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 4
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifdef BLOCK_STRIDED
#define STRIDED_MODE 1
#else
#define STRIDED_MODE 0
#endif

#ifdef __DOUBLE__
typedef double class_T;
#elif defined(__HALF__)
typedef half2 class_T;
#elif defined(class_T)
// class_T is already defined via -Dclass_T=type
#else
typedef float class_T;
#endif

#ifdef __HALF__
inline class_T my_conv_int(const int i) {
    half h = (half)i;
    return __halves2half2(h, h);
}

inline class_T my_mad(const class_T a, const class_T b, const class_T c) {
    return __hfma2(a, b, c);
}

inline bool my_equal(const class_T a, const class_T b) {
    return __hbeq2(a, b);
}
#else
inline class_T my_conv_int(const int i) {
    return (class_T)i;
}

inline class_T my_mad(const class_T a, const class_T b, const class_T c) {
    return a * b + c;
}

inline bool my_equal(const class_T a, const class_T b) {
    return a == b;
}
#endif

__kernel void benchmark_func(class_T seed, __global class_T *g_data) {
    const unsigned int blockSize = blockdim;
    const int stride = blockSize;

    int idx;
    if (STRIDED_MODE) {
        idx = get_group_id(0) * blockSize * ELEMENTS_PER_THREAD + get_local_id(0);
    } else {
        idx = get_global_id(0) * ELEMENTS_PER_THREAD;
    }

    const int big_stride = get_num_groups(0) * blockSize * ELEMENTS_PER_THREAD;

    class_T tmps[ELEMENTS_PER_THREAD];

    for (int k = 0; k < FUSION_DEGREE; k++) {
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];

            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
                tmps[j] = my_mad(tmps[j], tmps[j], seed);
            }
        }

        class_T sum = my_conv_int(0);
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
            sum = my_mad(tmps[j], tmps[j + 1], sum);
        }

        if (my_equal(sum, my_conv_int(-1))) {
            g_data[idx + k * big_stride] = sum;
        }
    }
}
